/**
 * Mock data for the Operations · Categories sub-page.
 * Each category is rated by how much capital it holds (capPct) vs how much
 * of total turnover it generates (velPct). A mismatch greater than ~6pp is
 * either a "trap" (capital sits but doesn't turn) or "starved" (turns hard
 * but isn't funded).
 */

export type CategoryKind = "trap" | "ok" | "starved";

export interface CatItem {
  /** Original index for stable references (assigned at module init) */
  idx: number;
  name: string;
  items: number;
  /** USD at cost */
  value: number;
  /** Percentage of inventory capital held */
  capPct: number;
  /** Percentage of company turnover this category generates */
  velPct: number;
  /** Annual inventory turns (×) */
  turns: number;
  /** capPct - velPct */
  mismatch: number;
  kind: CategoryKind;
}

const RAW: Array<Omit<CatItem, "idx" | "mismatch" | "kind">> = [
  { name: "Decor", items: 142, value: 247000, capPct: 29, velPct: 11, turns: 1.1 },
  { name: "Candles", items: 88, value: 138000, capPct: 16, velPct: 12, turns: 2.4 },
  { name: "Textiles", items: 64, value: 121000, capPct: 14, velPct: 9, turns: 1.8 },
  { name: "Tech & Cables", items: 96, value: 104000, capPct: 12, velPct: 17, turns: 4.6 },
  { name: "Packaging", items: 54, value: 78000, capPct: 9, velPct: 10, turns: 3.1 },
  { name: "Stationery", items: 71, value: 69000, capPct: 8, velPct: 8, turns: 3.0 },
  { name: "Accessories", items: 118, value: 78000, capPct: 9, velPct: 24, turns: 6.2 },
  { name: "Fragrance", items: 39, value: 31000, capPct: 3, velPct: 9, turns: 5.4 },
];

export const CATEGORIES: CatItem[] = RAW.map((c, i) => {
  const mismatch = c.capPct - c.velPct;
  const kind: CategoryKind = mismatch >= 6 ? "trap" : mismatch <= -6 ? "starved" : "ok";
  return { ...c, idx: i, mismatch, kind };
}).sort((a, b) => b.capPct - a.capPct);

