"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  CATEGORIES,
  KIND_LABEL,
  KIND_DETAIL_HEAD,
  categoriesAI,
  type CategoryKind,
  type CatItem,
} from "@/features/ops/api/ops-categories-data";
import "./categories.css";

type Filter = "all" | CategoryKind;

const fmtK = (v: number) =>
  Math.abs(v) >= 1000 ? `$${Math.round(v / 1000)}K` : `$${Math.round(v)}`;

const FILTER_KEYS: Filter[] = ["all", "trap", "ok", "starved"];
const FILTER_LABELS = ["All", "Over-invested", "Balanced", "Starved"];

const detailBodyHtml = (c: CatItem) => {
  if (c.kind === "trap") {
    const idle = c.value * (c.mismatch / c.capPct);
    return `Holds <strong>${c.capPct}%</strong> of inventory cash but turns only <strong>${c.velPct}%</strong> — a <strong>${c.mismatch}pp</strong> gap. Roughly <strong>${fmtK(idle)}</strong> is effectively idle here. Draw down the overhang and redeploy.`;
  }
  if (c.kind === "starved") {
    return `Turns <strong>${c.velPct}%</strong> of the business on just <strong>${c.capPct}%</strong> of capital — it's working harder than it's funded. This category can absorb more inventory and turn it. Fund it from a trapped category.`;
  }
  return `Capital share (<strong>${c.capPct}%</strong>) and turnover share (<strong>${c.velPct}%</strong>) are roughly aligned — money here is working at about the rate it's funded.`;
};

const bridgeLabel = (k: CategoryKind) =>
  k === "trap" ? "Free trapped capital" : k === "starved" ? "Fund this category" : "Review allocation";

export default function CategoriesPage() {
  const [filterIdx, setFilterIdx] = useState(0);
  const filter: Filter = FILTER_KEYS[filterIdx];
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [bridgeSent, setBridgeSent] = useState(false);

  const totalValue = useMemo(
    () => CATEGORIES.reduce((a, c) => a + c.value, 0),
    [],
  );
  const largest = useMemo(() => CATEGORIES[0], []);
  const slowValue = useMemo(
    () =>
      CATEGORIES.filter((c) => c.turns < 2.5).reduce((a, c) => a + c.value, 0),
    [],
  );
  const slowPct = Math.round((slowValue / totalValue) * 100);
  const trapCount = CATEGORIES.filter((c) => c.kind === "trap").length;
  const starvedCount = CATEGORIES.filter((c) => c.kind === "starved").length;

  const maxCap = useMemo(
    () => Math.max(...CATEGORIES.map((c) => c.capPct)),
    [],
  );
  const scale = 92 / maxCap;

  const visible = useMemo(() => {
    if (filter === "all") return CATEGORIES;
    return CATEGORIES.filter((c) => c.kind === filter);
  }, [filter]);

  const selected =
    selectedIdx === null
      ? null
      : CATEGORIES.find((c) => c.idx === selectedIdx) ?? null;

  const onSelect = (idx: number) => {
    setSelectedIdx((cur) => (cur === idx ? null : idx));
  };
  const sendBridge = () => {
    setBridgeSent(true);
    setTimeout(() => setBridgeSent(false), 1700);
  };

  return (
    <div className="ops-categories-page">
      <DeptHeader
        dept="ops"
        title="Categories"
        meta={
          <>
            <span className="live">Live</span> · Where capital is concentrated — and whether it&rsquo;s in the right categories
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="rebalance">Rebalance → Bridge</BridgePrimaryButton>
            <BridgePrimaryButton dept="ops" page="add-category">+ Add Category →</BridgePrimaryButton>
          </>
        }
      />

      {/* Filter row — uses PeriodTabs for canonical Y rhythm */}
      <PeriodTabs
        labels={FILTER_LABELS}
        activeIndex={filterIdx}
        onChange={setFilterIdx}
      />

      {/* KPI strip */}
      <div className="cat-kpis">
        <div className="cat-kpi">
          <div className="lbl">Inventory value · at cost</div>
          <div className="val">{fmtK(totalValue)}</div>
          <div className="sub">{CATEGORIES.length} active categories</div>
        </div>
        <div className="cat-kpi">
          <div className="lbl">Largest category</div>
          <div className="val">{largest.name}</div>
          <div className="sub">
            {fmtK(largest.value)} · {largest.capPct}% of capital
          </div>
        </div>
        <div className="cat-kpi">
          <div className="lbl">Capital in slow-movers</div>
          <div className="val loss">{slowPct}%</div>
          <div className="sub">{fmtK(slowValue)} turning below blended</div>
        </div>
        <div className="cat-kpi">
          <div className="lbl">Trapped vs starved</div>
          <div className="val">
            {trapCount} / {starvedCount}
          </div>
          <div className="sub">over-invested vs under-funded</div>
        </div>
      </div>

      {/* AI strip */}
      <AIStrip label={categoriesAI.label} meta={categoriesAI.meta} cards={categoriesAI.cards} />

      {/* Capital vs velocity ranked bars */}
      <div className="cat-section-label">
        Capital vs velocity
        <span className="count">where money sits vs how fast it turns</span>
        <a className="gohint" href="/ops/velocity">Drill to SKUs in Velocity →</a>
      </div>
      <div className="cap-rank">
        <div className="cr-legend">
          <span className="lg">
            <i className="cap" />
            Capital held (% of inventory cash)
          </span>
          <span className="lg">
            <i className="vel" />
            Velocity (% of turnover)
          </span>
          <span className="note">
            Bar past the marker = trapped capital · marker past the bar = starved
          </span>
        </div>
        {CATEGORIES.map((c) => {
          const capW = (c.capPct * scale).toFixed(1);
          const velX = (c.velPct * scale).toFixed(1);
          const sign = c.mismatch > 0 ? "+" : "";
          return (
            <div
              key={c.idx}
              className={`caprow${selectedIdx === c.idx ? " sel" : ""}`}
              onClick={() => onSelect(c.idx)}
            >
              <div>
                <div className="cap-name">{c.name}</div>
                <div className="cap-sub">
                  {fmtK(c.value)} · {c.items} items · {c.turns}× turns
                </div>
              </div>
              <div className="cap-track">
                <div className="cap-axis" />
                <div
                  className={`cap-fill ${c.kind === "ok" ? "" : c.kind}`}
                  style={{ width: `${capW}%` }}
                />
                <div className="cap-vel" style={{ left: `${velX}%` }}>
                  <span className="cap-vlabel">turns {c.velPct}%</span>
                </div>
              </div>
              <div className="cap-verdict">
                <div className={`cap-mismatch ${c.kind}`}>
                  {sign}
                  {c.mismatch}pp
                </div>
                <div className={`cap-flag ${c.kind}`}>{KIND_LABEL[c.kind]}</div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Cards grid + slide-in detail */}
      <div className="cat-section-label">
        By category
        <span className="count">
          {CATEGORIES.length} categories · {fmtK(totalValue)} at cost
        </span>
      </div>

      <div className={`led-split${selected ? " open" : ""}`}>
        <div className="led-main">
          <div className="cat-grid">
            {visible.length === 0 ? (
              <div className="cat-empty">No categories in this view</div>
            ) : (
              visible.map((c) => (
                <div
                  key={c.idx}
                  className={`catcard${c.kind === "ok" ? "" : ` ${c.kind}`}${
                    selectedIdx === c.idx ? " sel" : ""
                  }`}
                  onClick={() => onSelect(c.idx)}
                >
                  <div className="cc-top">
                    <div>
                      <div className="cc-name">{c.name}</div>
                      <div className="cc-items">{c.items} items</div>
                    </div>
                    <span className={`cc-flag ${c.kind}`}>
                      {KIND_LABEL[c.kind]}
                    </span>
                  </div>
                  <div className="cc-val">
                    {fmtK(c.value)}
                    <span className="u">at cost</span>
                  </div>
                  <div className="cc-meta">
                    <div className="cc-m">
                      <div className="ml">Capital</div>
                      <div className="mv">{c.capPct}%</div>
                    </div>
                    <div className="cc-m">
                      <div className="ml">Turnover</div>
                      <div className="mv">{c.velPct}%</div>
                    </div>
                    <div className="cc-m">
                      <div className="ml">Mismatch</div>
                      <div
                        className={`mv ${
                          c.kind === "trap"
                            ? "red"
                            : c.kind === "starved"
                            ? "green"
                            : ""
                        }`}
                      >
                        {c.mismatch > 0 ? "+" : ""}
                        {c.mismatch}pp
                      </div>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        <aside className="led-detail">
          <div className="led-detail-in">
            {!selected ? (
              <div className="cd-empty">
                <div className="ttl">Capital lens</div>
                <div className="lead">
                  Click a category to see how much capital it holds, how fast that capital turns, and whether it&rsquo;s trapping cash or starving for it — then rebalance via the Bridge.
                </div>
              </div>
            ) : (
              <>
                <div className="cd-head">
                  <div>
                    <div className="cd-name">{selected.name}</div>
                    <div className="cd-meta">
                      {selected.items} items · {fmtK(selected.value)} at cost
                    </div>
                  </div>
                  <button
                    className="cd-clear"
                    onClick={() => setSelectedIdx(null)}
                  >
                    clear ✕
                  </button>
                </div>

                <div className={`cd-verdict ${selected.kind}`}>
                  <div className="cd-vh">{KIND_DETAIL_HEAD[selected.kind]}</div>
                  <div
                    className="cd-vb"
                    dangerouslySetInnerHTML={{ __html: detailBodyHtml(selected) }}
                  />
                </div>

                <div className="cd-stats">
                  <div className="cd-stat">
                    <span className="sl">Capital held</span>
                    <span className="sv">{selected.capPct}%</span>
                  </div>
                  <div className="cd-stat">
                    <span className="sl">Turnover share</span>
                    <span className="sv">{selected.velPct}%</span>
                  </div>
                  <div className="cd-stat">
                    <span className="sl">Mismatch</span>
                    <span
                      className={`sv ${
                        selected.kind === "trap"
                          ? "red"
                          : selected.kind === "starved"
                          ? "green"
                          : ""
                      }`}
                    >
                      {selected.mismatch > 0 ? "+" : ""}
                      {selected.mismatch}pp
                    </span>
                  </div>
                  <div className="cd-stat">
                    <span className="sl">Annual turns</span>
                    <span className="sv">{selected.turns}×</span>
                  </div>
                </div>

                <div className="cd-share">
                  <div className="cd-share-l">
                    <span>Capital vs velocity</span>
                    <span>
                      {selected.capPct}% held · {selected.velPct}% turns
                    </span>
                  </div>
                  <div className="cd-share-bar">
                    <div
                      className={`cd-share-cap ${selected.kind === "ok" ? "" : selected.kind}`}
                      style={{
                        width: `${((selected.capPct / maxCap) * 92).toFixed(1)}%`,
                      }}
                    />
                    <div
                      className="cd-share-vel"
                      style={{
                        left: `${((selected.velPct / maxCap) * 92).toFixed(1)}%`,
                      }}
                    />
                  </div>
                </div>

                <button
                  className={`cd-bridge${bridgeSent ? " sent" : ""}`}
                  onClick={sendBridge}
                >
                  {bridgeSent
                    ? "Sent to Bridge ✓"
                    : `${bridgeLabel(selected.kind)} → Bridge`}
                </button>
                <button
                  className="cd-bridge secondary"
                  onClick={() => {
                    window.location.href = "/ops/velocity";
                  }}
                >
                  See SKUs in Velocity
                </button>
              </>
            )}
          </div>
        </aside>
      </div>
    </div>
  );
}
