"use client";

/* ════════════════════════════════════════════════════════════════════════
   PeriodTabs — the pill-track time selector.
   Same styling everywhere; label set is per-page (Growth uses short ranges,
   most rooms use MTD / 30d / 6mo / 12mo / Custom).

   Opt-in (backward compatible):
   - accent  → the active tab label is tinted the room's dept color.
   - keys    → each tab carries a period key; a resolved date-range chip
               renders below ("Last 7 days" → "May 20 – May 26 · 7 days").
   When neither is passed, it renders exactly as before (white active pill,
   ink label, no chip).
   ════════════════════════════════════════════════════════════════════════ */

import { useState } from "react";
import { resolvePeriodRange, inferKeys, type PeriodKey } from "@/lib/period-range";

export interface PeriodTabsProps {
  labels: string[];
  /** Index of the active tab. If `onChange` is omitted, the component manages its own state. */
  activeIndex?: number;
  onChange?: (i: number) => void;
  /** marginBottom override — default 32px (the canonical spacing under the dept header) */
  marginBottom?: number | string;
  /** Per-tab period keys (parallel to labels). Optional — inferred from labels when omitted. */
  keys?: PeriodKey[];
  /** Dept accent (e.g. "var(--d-growth)") — tints the active tab label. */
  accent?: string;
  /** Force the date-range chip on/off. Default: auto (shown when labels resolve to periods). */
  showRange?: boolean;
}

export function PeriodTabs({ labels, activeIndex, onChange, marginBottom = 32, keys, accent, showRange }: PeriodTabsProps) {
  const [internal, setInternal] = useState(0);
  const active = activeIndex ?? internal;
  const handle = (i: number) => {
    if (onChange) onChange(i);
    else setInternal(i);
  };

  // Keys come explicitly or are inferred from the labels (device/forecast
  // toggles don't resolve → no chip). showRange can force it off.
  const resolvedKeys = keys ?? inferKeys(labels);
  const show = resolvedKeys != null && resolvedKeys.length === labels.length && showRange !== false;
  const range = show && resolvedKeys ? resolvePeriodRange(resolvedKeys[active]) : null;

  return (
    <>
      <div className="period-tabs" style={{ marginBottom: show ? 10 : marginBottom }}>
        {labels.map((label, i) => (
          <button
            key={i}
            className={i === active ? "active" : ""}
            onClick={() => handle(i)}
            type="button"
            style={i === active && accent ? { color: accent } : undefined}
          >
            {label}
          </button>
        ))}
      </div>
      {range && (
        // Styled inline (not via a CSS class) so the white chip renders reliably
        // regardless of CSS-layer ordering / dev HMR state. Mirrors the demo's
        // resolved-range chip: white, hairline border, mono.
        <div
          className="period-range"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 7,
            marginLeft: 2,
            marginBottom,
            padding: "7px 13px",
            background: "#fff",
            border: "0.5px solid var(--ink-line)",
            borderRadius: 7,
            fontFamily: "var(--font-mono)",
            fontSize: "10.5px",
            letterSpacing: "0.05em",
            color: "var(--ink-3)",
            width: "fit-content",
          }}
        >
          {/* Explicit width/height/fill on the SVG itself — without them, Tailwind
             Preflight's `svg{display:block}` lets a viewBox-only SVG balloon to fill
             its container with a default black <rect> fill (the "big black box"). */}
          <svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" strokeWidth={1.8} style={{ flexShrink: 0 }}>
            <rect x="3" y="4" width="18" height="18" rx="2" />
            <line x1="3" y1="9" x2="21" y2="9" />
            <line x1="8" y1="2" x2="8" y2="6" />
            <line x1="16" y1="2" x2="16" y2="6" />
          </svg>
          <span>
            <b style={{ color: "var(--ink-2)", fontWeight: 500 }}>{range.text}</b>
            {range.count ? ` ${range.count}` : ""}
          </span>
        </div>
      )}
    </>
  );
}
